def gen(rng, size):
    import string
    n = max(1, min(size, 2000))
    def word():
        L = rng.randint(1, 10)
        return ''.join(rng.choice('abcde') for _ in range(L))
    queries = [word() for _ in range(rng.randint(1, n))]
    words = [word() for _ in range(rng.randint(1, n))]
    return [queries, words]

