class Solution:
    def numSmallerByFrequency(self, queries, words):
        def f(s):
            m = min(s)
            return s.count(m)
        wscores = [f(w) for w in words]
        res = []
        for q in queries:
            fq = f(q)
            res.append(sum(1 for w in wscores if w > fq))
        return res

