class Solution:
    def numSmallerByFrequency(self, queries, words):
        import bisect
        def f(s):
            m = min(s)
            return s.count(m)
        ws = sorted(f(w) for w in words)
        n = len(ws)
        return [n - bisect.bisect_right(ws, f(q)) for q in queries]

