var numSmallerByFrequency = function(queries, words) {
    const f = s => {
        let m = 'z';
        for (const c of s) if (c < m) m = c;
        let cnt = 0;
        for (const c of s) if (c === m) cnt++;
        return cnt;
    };
    const ws = words.map(f).sort((a, b) => a - b);
    const n = ws.length;
    const upper = (arr, x) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] <= x) lo = mid + 1; else hi = mid;
        }
        return lo;
    };
    return queries.map(q => n - upper(ws, f(q)));
};
